window.SmartRisk=window.SmartRisk||{};(function(){const SR=SmartRisk;function render(){const metrics=SR.MockData.metrics.map(m=>SR.Card.metric(m)).join(""),progress=SR.MockData.progress.map(i=>`<div><div class="progress-head"><span>${i.label}</span><strong>${i.value}%</strong></div><div class="progress-track"><div class="progress-value" style="width:${i.value}%"></div></div></div>`).join(""),activities=SR.MockData.activities.map(i=>`<div class="activity-item"><span class="activity-dot"></span><div><p>${i.text}</p><span class="activity-time">${i.time}</span></div></div>`).join("");return `<section class="hero-card"><div class="hero-grid"><div><span class="kicker" style="color:#ffd795">Sprint 1.2B</span><h1 class="hero-title">Gestión territorial del riesgo, integrada y visible.</h1><p class="hero-copy">SmartRisk CZ5 consolida seguimiento documental, territorial y operativo en una interfaz institucional.</p></div><div class="hero-stat"><strong>76%</strong><span>Avance general demostrativo del sistema zonal</span></div></div></section><section class="page-header"><div><span class="kicker">Panel ejecutivo</span><h2 class="page-title">Dashboard institucional</h2><p class="page-subtitle">Indicadores, tendencias y seguimiento territorial.</p></div><div class="split-actions">${SR.Button.render({id:"go-territories",label:"Abrir territorios",icon:"map"})}</div></section><section class="metric-grid">${metrics}</section><section class="content-grid"><div class="stack">${SR.Card.panel({title:"Tendencia mensual de avance",badge:"Enero–julio",body:SR.Chart.line(SR.MockData.trend)})}${SR.Card.panel({title:"Avance por línea de gestión",body:`<div class="progress-list">${progress}</div>`})}</div><div class="stack">${SR.Card.panel({title:"Actividad reciente",body:`<div class="activity-list">${activities}</div>`})}${SR.Card.panel({title:"Siguiente módulo",body:'<p>El módulo Territorios ya cuenta con filtros, mapa esquemático, detalle y exportación CSV.</p><a class="btn btn-primary" href="#/territorios">Revisar territorios</a>'})}</div></section>`}function bind(){document.getElementById("go-territories")?.addEventListener("click",()=>location.hash="/territorios")}SR.DashboardModule={route:{path:"/dashboard",title:"Dashboard",render,bind}}})();